function restoreTriplet(sourceDir: string, dbDir: string): number {
  let restored = 0;
  for (const fileName of DB_TRIPLET) {
    const source = join(sourceDir, fileName);
    if (!existsSync(source)) {
      continue;
    }
    copyFileSync(source, tripletPath(dbDir, fileName));
    restored += 1;
  }
